import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";const i=JSON.parse(`{"title":"Посібник для розробників","description":"Наші посібники для розробників, написані спільнотою, охоплюють багато тем, починаючи від створення мода та налаштування вашого середовища, аж до рендера, роботи в мережі, генерація даних тощо.","frontmatter":{"title":"Посібник для розробників","description":"Наші посібники для розробників, написані спільнотою, охоплюють багато тем, починаючи від створення мода та налаштування вашого середовища, аж до рендера, роботи в мережі, генерація даних тощо.","authors":["IMB11","its-miroma","itsmiir"],"authors-nogithub":["basil4088"],"resources":{"https://github.com/FabricMC":"Організація FabricMC на GitHub","https://github.com/FabricMC/fabric-docs/tree/main/reference/latest":"ExampleMod, на який посилаються у цій документації"},"files":[]},"headers":[],"relativePath":"uk_ua/develop/index.md","filePath":"translated/uk_ua/develop/index.md","lastUpdated":1774518827000}`);var a={name:`uk_ua/develop/index.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Посібник для розробників <a class="header-anchor" href="#h1" aria-label="Permalink to “Посібник для розробників”">​</a></h1><p>Fabric — це легкий інструментарій модифікації для Minecraft: Java Edition, розроблений, щоб бути простим і легким у використанні. Це дозволяє розробникам застосовувати модифікації («моди») до стандартної гри, додавати нові функції або змінювати наявні механіки.</p><p>Ця документація проведе вас через модифікацію за допомогою Fabric, від <a href="./getting-started/creating-a-project">створення вашого першого мода</a> і <a href="./getting-started/setting-up">налаштування вашого середовища</a>, до складних тем, як-от <a href="./rendering/basic-concepts">рендер</a>, <a href="./networking">мережа</a>, <a href="./data-generation/setup">генерація даних</a> тощо.</p><p>Перегляньте список доступних сторінок на боковій панелі.</p><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>Якщо вам це знадобиться в будь-який час, повністю робочий мод з усім вихідним кодом цієї документації доступний у теці <a href="https://github.com/FabricMC/fabric-docs/tree/main/reference/latest" target="_blank" rel="noreferrer"><code>/reference</code> на GitHub</a>.</p></div><h2 id="prerequisites" tabindex="-1">Передумови <a class="header-anchor" href="#prerequisites" aria-label="Permalink to “Передумови”">​</a></h2><p>Перш ніж розпочати модифікацію за допомогою Fabric, вам потрібно мати певне розуміння розробки за допомогою Java та об&#39;єктноорієнтованого програмування загалом.</p><p>Ось деякі ресурси, які можуть допомогти вам ознайомитися з Java та ООП:</p><ul><li><a href="https://www.w3schools.com/java/" target="_blank" rel="noreferrer">W3: Посібник з Java</a></li><li><a href="https://www.codecademy.com/learn/learn-java" target="_blank" rel="noreferrer">Codecademy: Учіться Java</a></li><li><a href="https://www.w3schools.com/java/java_oop.asp" target="_blank" rel="noreferrer">W3: Java ООП</a></li><li><a href="https://medium.com/@Adekola_Olawale/beginners-guide-to-object-oriented-programming-a94601ea2fbd" target="_blank" rel="noreferrer">Medium: Вступ до ООП</a></li></ul><h2 id="what-does-fabric-offer" tabindex="-1">Що пропонує Fabric? <a class="header-anchor" href="#what-does-fabric-offer" aria-label="Permalink to “Що пропонує Fabric?”">​</a></h2><p>Проєкт Fabric зосереджений навколо трьох основних компонентів:</p><ul><li><strong>Завантажувач Fabric</strong>: гнучкий, незалежний від платформи Завантажувач модів, в основному розроблений для Minecraft: Java Edition</li><li><strong>Fabric API</strong>: додатковий набір API та інструментів, які розробники модів можуть використовувати під час створення модів</li><li><strong>Fabric Loom</strong>: плаґін <a href="https://gradle.org/" target="_blank" rel="noreferrer">Gradle</a>, який дозволяє розробникам легко розробляти та налагоджувати моди</li></ul><h3 id="what-does-fabric-api-offer" tabindex="-1">Що пропонує Fabric API? <a class="header-anchor" href="#what-does-fabric-api-offer" aria-label="Permalink to “Що пропонує Fabric API?”">​</a></h3><p>Fabric API надає широкий набір API, які створюються на основі функціональних можливостей, щоб забезпечити розширену або спрощену розробку.</p><p>Наприклад, він надає нові перехоплювачі, події, утиліти, такі як розширювачі транзитивного доступу, доступ до внутрішніх реєстрів, таких як реєстр компостованих предметів, тощо.</p>`,15)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};